// Style: Classic Observer
interface WindObserver491 {
    void onSpeedChanged(double speed);
}
class TurbineCtrl491 implements WindObserver491 {
    public void onSpeedChanged(double speed) {
        System.out.println("TurbineCtrl received SpeedChanged: " + speed);
    }
}
class WeatherLogger491 implements WindObserver491 {
    public void onSpeedChanged(double speed) {
        System.out.println("WeatherLogger received SpeedChanged: " + speed);
    }
}
class WindSubject491 {
    private final java.util.List<WindObserver491> observers = new java.util.ArrayList<>();
    private double speed = 0.0;
    public void addObserver(WindObserver491 o) { observers.add(o); }
    public void removeObserver(WindObserver491 o) { observers.remove(o); }
    public void setSpeed(double speed) {
        this.speed = speed;
        notifyObservers();
    }
    private void notifyObservers() {
        for (WindObserver491 o : observers) o.onSpeedChanged(speed);
    }
}

